import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Container, Row, Col, Card, Form, Button, Alert } from 'react-bootstrap';

const DebugLogin = () => {
  const { authFetch } = useAuth();
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    console.log('DEBUG: Submitting password:', password);
    console.log('DEBUG: Password length:', password.length);
    console.log('DEBUG: Password trimmed:', password.trim());

    try {
      // Direct fetch instead of authFetch to isolate the issue
      const response = await fetch('http://localhost:5000/api/debug/data', {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${password.trim()}`
        }
      });

      console.log('DEBUG: Response status:', response.status);
      console.log('DEBUG: Response ok:', response.ok);

      if (response.ok) {
        const data = await response.json();
        console.log('DEBUG: Login successful, data:', data);
        // Store debug token in sessionStorage for debug dashboard
        sessionStorage.setItem('debugToken', password.trim());
        navigate('/debug');
      } else {
        console.log('DEBUG: Login failed');
        const errorData = await response.json();
        console.log('DEBUG: Error response:', errorData);
        setError('Invalid debug password');
      }
    } catch (err) {
      console.log('DEBUG: Exception occurred:', err);
      setError('Debug access failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container className="mt-4">
      <Row className="justify-content-center">
        <Col md={6}>
          <Card>
            <Card.Header>
              <h4 className="text-center">🔍 Debug Access</h4>
            </Card.Header>
            <Card.Body>
              <Alert variant="info" className="mb-3">
                <strong>Debug Dashboard Access</strong><br/>
                Enter debug password to access system data and user information.
                <br/><br/>
                <strong>Hint:</strong> The password is <code>debug123</code>
              </Alert>

              <Form onSubmit={handleSubmit}>
                <Form.Group className="mb-3">
                  <Form.Label>Debug Password</Form.Label>
                  <Form.Control
                    type="password"
                    placeholder="Enter debug password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    required
                  />
                </Form.Group>

                {error && <Alert variant="danger">{error}</Alert>}

                <Button variant="primary" type="submit" disabled={loading}>
                  {loading ? 'Accessing...' : 'Access Debug Dashboard'}
                </Button>
              </Form>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </Container>
  );
};

export default DebugLogin;
